library(tidyverse)
library(patchwork)
library(ggrepel)

dat <- read_csv("data/N2O_summary_data_04012026.csv", show_col_types = FALSE)
dir.create("plots/figures", showWarnings = FALSE, recursive = TRUE)

model_labels <- c("Wang" = "Linear model", "Qiu" = "Quadratic model")

# ── Load pre-computed components and national summary ─────────────────────────
# Generated by data_prep.R. Qiu filter already applied (avoided < 0 set to 0).
load("data/avoided_emissions_components.Rdata")

# ============================================================
# FIGURE 1 — DOT PLOTS: national totals, EBK pH model
# ============================================================
# Source: summary_total from avoided_emissions_components.Rdata (via data_prep.R).
# Qiu filter already applied. NReductionOnly duplicated across Avg/Max so it
# appears in both pH target panels.
# Two versions:
#   A. fig1_dotplot_ebk_phtarget.png — facet = EF model, color = pH target
#   B. fig1_dotplot_ebk_efmodel.png  — facet = pH target, color = EF model

dot_base <- bind_rows(
    summary_total |>
      filter(n_scenario %in% c("NActual", "Combined"), ph_target %in% c("Avg", "Max")),
    summary_total |>
      filter(n_scenario == "NReductionOnly") |>
      select(-ph_target) |>
      crossing(ph_target = c("Avg", "Max"))
  ) |>
  filter(ph_model == "EBK") |>
  mutate(
    ef_label = factor(recode(ef_model, !!!model_labels), levels = unname(model_labels)),
    ph_label = factor(ph_target, levels = c("Avg", "Max"),
                      labels = c("Average recommended pH", "Maximum recommended pH")),
    scenario_label = factor(recode(n_scenario,
      NActual        = "pH management\nonly",
      NReductionOnly = "N reduction\nonly",
      Combined       = "Both\ncombined"
    ), levels = c("pH management\nonly", "N reduction\nonly", "Both\ncombined")),
    x_num = as.integer(scenario_label),
    y_val = avoided_mean_kgN / 1e6,
    y_sd  = avoided_sd_kgN  / 1e6
  )

dot_theme <- list(
  theme_bw(),
  theme(
    legend.position       = "bottom",
    plot.caption          = element_text(size = 8, hjust = 0, color = "grey35",
                                         margin = margin(t = 6), lineheight = 1.3),
    plot.caption.position = "plot"
  )
)

shared_caption <- paste0(
  "EBK soil pH model. Quadratic model: counties where liming results in a net increase in N\u2082O ",
  "(avoided emissions < 0) set to zero. Error bars = \u00b11 SD."
)

# Plot A: facet = EF model, color = pH target
ph_colors <- c("Average recommended pH" = "#fec44f", "Maximum recommended pH" = "#7f2704")

fig_dot_phtarget <- ggplot(
    mutate(dot_base, x_nudge = if_else(ph_target == "Avg", -0.12, 0.12)),
    aes(x = x_num + x_nudge, y = y_val, color = ph_label)
  ) +
  geom_errorbar(aes(ymin = y_val - y_sd, ymax = y_val + y_sd),
                width = 0.08, linewidth = 0.7) +
  geom_point(size = 3.5) +
  scale_x_continuous(breaks = 1:3,
                     labels = c("pH management\nonly", "N reduction\nonly", "Both\ncombined"),
                     limits = c(0.5, 3.5)) +
  facet_wrap(~ef_label, ncol = 2) +
  scale_color_manual(name = "pH target", values = ph_colors) +
  labs(x = NULL, y = "Avoided N\u2082O-N (kt)",
       caption = paste0(shared_caption,
         " N reduction only: Avg and Max dots overlap \u2014 ",
         "pH target does not affect this scenario.")) +
  dot_theme

ggsave("plots/figures/fig1_dotplot_ebk_phtarget.png",
       fig_dot_phtarget, width = 8, height = 5, dpi = 300)
message("Saved fig1_dotplot_ebk_phtarget")

# Plot B: facet = pH target, color = EF model
ef_colors <- c("Linear model" = "#d95f0e", "Quadratic model" = "#7f2704")

fig_dot_efmodel <- ggplot(
    mutate(dot_base, x_nudge = if_else(ef_model == "Wang", -0.12, 0.12)),
    aes(x = x_num + x_nudge, y = y_val, color = ef_label)
  ) +
  geom_errorbar(aes(ymin = y_val - y_sd, ymax = y_val + y_sd),
                width = 0.08, linewidth = 0.7) +
  geom_point(size = 3.5) +
  scale_x_continuous(breaks = 1:3,
                     labels = c("pH management\nonly", "N reduction\nonly", "Both\ncombined"),
                     limits = c(0.5, 3.5)) +
  facet_wrap(~ph_label, ncol = 2) +
  scale_color_manual(name = "N\u2082O model", values = ef_colors) +
  labs(x = NULL, y = "Avoided N\u2082O-N (kt)",
       caption = paste0(shared_caption,
         " N reduction only: values are identical across pH panels \u2014 ",
         "pH target does not affect this scenario.")) +
  dot_theme

ggsave("plots/figures/fig1_dotplot_ebk_efmodel.png",
       fig_dot_efmodel, width = 8, height = 5, dpi = 300)
message("Saved fig1_dotplot_ebk_efmodel")

# ============================================================
# FIGURE 2 — STATE STACKED BAR: avoided N2O-N by state and crop
# ============================================================
# EBK pH model, Max pH target, combined scenario.
# States ordered independently within each EF model panel.

# Paul Tol "muted" palette — colorblind-safe
crop_colors <- c(
  "Barley"       = "#88CCEE",
  "Corn"         = "#999933",
  "Cotton"       = "#117733",
  "Durum Wheat"  = "#AA4499",
  "Rice"         = "#882255",
  "Sorghum"      = "#CC6677",
  "Spring Wheat" = "#44AA99",
  "Winter Wheat" = "#332288"
)

state_crop_dat <- components |>
  filter(ph_model == "EBK", ph_target == "Max") |>
  group_by(State, Crop, ef_model) |>
  summarise(combined_kt = sum(combined, na.rm = TRUE) / 1e6, .groups = "drop") |>
  mutate(ef_label = factor(recode(ef_model, !!!model_labels), levels = unname(model_labels)))

state_order_wang <- state_crop_dat |> filter(ef_model == "Wang") |>
  group_by(State) |> summarise(total = sum(combined_kt)) |> arrange(total) |> pull(State)
state_order_qiu  <- state_crop_dat |> filter(ef_model == "Qiu") |>
  group_by(State) |> summarise(total = sum(combined_kt)) |> arrange(total) |> pull(State)

make_state_panel <- function(df, efm, state_order, xlim, show_legend = FALSE) {
  ggplot(
    df |> filter(ef_model == efm) |> mutate(State = factor(State, levels = state_order)),
    aes(y = State, x = combined_kt, fill = Crop)
  ) +
    geom_col() +
    scale_fill_manual(values = crop_colors, name = "Crop") +
    scale_x_continuous(labels = scales::comma, limits = c(0, xlim)) +
    labs(title = as.character(unique(df$ef_label[df$ef_model == efm])),
         x = "Avoided N\u2082O-N (kt)", y = NULL) +
    theme_bw() +
    theme(legend.position = if (show_legend) "right" else "none",
          plot.title = element_text(size = 11))
}

stacked_caption <- theme(plot.caption = element_text(size = 8, hjust = 0, color = "grey35",
                                                      margin = margin(t = 6), lineheight = 1.3))

xlim_state <- state_crop_dat |>
  group_by(ef_model, State) |> summarise(total = sum(combined_kt), .groups = "drop") |>
  pull(total) |> max()

fig_state_crop <- make_state_panel(state_crop_dat, "Wang", state_order_wang, xlim_state) +
  make_state_panel(state_crop_dat, "Qiu", state_order_qiu, xlim_state, show_legend = TRUE) +
  plot_annotation(
    title   = "Avoided N\u2082O by state and crop (Max recommended pH, combined scenario)",
    caption = "EBK soil pH model; Max recommended pH target; combined scenario (pH management + N reduction).\nEach panel ordered by that model\u2019s total avoided emissions.",
    theme   = stacked_caption
  )

ggsave("plots/figures/fig2_state_crop_stacked.png", fig_state_crop,
       width = 12, height = 10, dpi = 300)
message("Saved fig2_state_crop_stacked")

# Top 10 states per model
state_totals <- state_crop_dat |>
  group_by(ef_model, State) |>
  summarise(total = sum(combined_kt), .groups = "drop")

top10_wang <- state_totals |> filter(ef_model == "Wang") |>
  slice_max(total, n = 10) |> arrange(total) |> pull(State)
top10_qiu  <- state_totals |> filter(ef_model == "Qiu")  |>
  slice_max(total, n = 10) |> arrange(total) |> pull(State)

make_top10_panel <- function(df, efm, state_order, xlim, show_legend = FALSE) {
  ggplot(
    df |> filter(ef_model == efm, State %in% state_order) |>
      mutate(State = factor(State, levels = state_order)),
    aes(y = State, x = combined_kt, fill = Crop)
  ) +
    geom_col() +
    scale_fill_manual(values = crop_colors, name = "Crop") +
    scale_x_continuous(labels = scales::comma, limits = c(0, xlim)) +
    labs(title = as.character(unique(df$ef_label[df$ef_model == efm])),
         x = "Avoided N\u2082O-N (kt)", y = NULL) +
    theme_bw() +
    theme(legend.position = if (show_legend) "right" else "none",
          plot.title = element_text(size = 11))
}

xlim_top10 <- state_crop_dat |>
  filter(State %in% c(top10_wang, top10_qiu)) |>
  group_by(ef_model, State) |> summarise(total = sum(combined_kt), .groups = "drop") |>
  pull(total) |> max()

fig_state_crop_top10 <- make_top10_panel(state_crop_dat, "Wang", top10_wang, xlim_top10) +
  make_top10_panel(state_crop_dat, "Qiu", top10_qiu, xlim_top10, show_legend = TRUE) +
  plot_annotation(
    title   = "Top 10 states: avoided N\u2082O by crop (Max recommended pH, combined scenario)",
    caption = "EBK soil pH model; Max recommended pH target; combined scenario (pH management + N reduction).\nTop 10 states ranked and ordered separately within each model panel.",
    theme   = stacked_caption
  )

ggsave("plots/figures/fig2_state_crop_stacked_top10.png", fig_state_crop_top10,
       width = 12, height = 6, dpi = 300)
message("Saved fig2_state_crop_stacked_top10")

# ============================================================
# FIGURES 3 & 4 — BUBBLE PLOTS: pH gap × N input × per-acre avoided
# ============================================================
# Per-acre avoided = county avoided N2O-N (kg) / harvested area (acres)
# EBK pH model, Max pH target, combined scenario.

peracre_dat <- components |>
  filter(ph_model == "EBK") |>
  left_join(
    dat |> distinct(State, County, Crop, Average_Area),
    by = c("State", "County", "Crop")
  ) |>
  filter(!is.na(Average_Area), Average_Area > 0) |>
  mutate(
    pH_only_per_acre  = pH_only  / Average_Area,
    N_only_per_acre   = N_only   / Average_Area,
    combined_per_acre = combined / Average_Area,
    ef_label = factor(recode(ef_model, !!!model_labels), levels = unname(model_labels))
  )

bubble_src <- dat |>
  distinct(State, County, Crop, Average_Area, Actual_N_input,
           Total_N_Actual, Total_N_Reduced, MeanEBK, pH_Max) |>
  filter(!is.na(Actual_N_input), Actual_N_input > 0,
         !is.na(Average_Area), Average_Area > 0) |>
  mutate(
    ph_gap           = pH_Max - MeanEBK,
    n_surplus_per_acre = (Total_N_Actual - Total_N_Reduced) / Average_Area
  )

# Area-weighted crop means
bubble_crop <- peracre_dat |>
  filter(ph_target == "Max") |>
  inner_join(bubble_src |> select(-Average_Area), by = c("State", "County", "Crop")) |>
  group_by(Crop, ef_model, ef_label) |>
  summarise(
    mean_ph_gap            = weighted.mean(ph_gap,             w = Average_Area, na.rm = TRUE),
    mean_n_per_acre        = weighted.mean(Actual_N_input,     w = Average_Area, na.rm = TRUE),
    mean_n_surplus_per_acre = weighted.mean(n_surplus_per_acre, w = Average_Area, na.rm = TRUE),
    mean_avoided_per_acre  = sum(combined_per_acre * Average_Area, na.rm = TRUE) /
                             sum(Average_Area,        na.rm = TRUE),
    .groups = "drop"
  ) |>
  mutate(model_label = factor(
    if_else(ef_model == "Wang", "Linear model (Wang)", "Quadratic model (Qiu)"),
    levels = c("Linear model (Wang)", "Quadratic model (Qiu)")
  ))

# FIGURE 3: size = per-acre avoided, fill = crop, border = EF model
model_borders <- c("Linear model (Wang)" = "grey45", "Quadratic model (Qiu)" = "grey10")

# FIGURE 4: same axes, fill = pH management share
bubble_share <- peracre_dat |>
  filter(ph_target == "Max") |>
  inner_join(bubble_src |> select(State, County, Crop, Actual_N_input, ph_gap, n_surplus_per_acre),
             by = c("State", "County", "Crop")) |>
  group_by(Crop, ef_model, ef_label) |>
  summarise(
    mean_ph_gap             = weighted.mean(ph_gap,              w = Average_Area, na.rm = TRUE),
    mean_n_per_acre         = weighted.mean(Actual_N_input,      w = Average_Area, na.rm = TRUE),
    mean_n_surplus_per_acre = weighted.mean(n_surplus_per_acre,  w = Average_Area, na.rm = TRUE),
    mean_avoided_per_acre   = sum(combined_per_acre * Average_Area, na.rm = TRUE) /
                              sum(Average_Area,        na.rm = TRUE),
    ph_fraction             = sum(pH_only_per_acre  * Average_Area, na.rm = TRUE) /
                            sum(combined_per_acre  * Average_Area, na.rm = TRUE),
    .groups = "drop"
  ) |>
  mutate(pt_size = scales::rescale(sqrt(mean_avoided_per_acre), to = c(3, 18),
                                   from = sqrt(range(mean_avoided_per_acre, na.rm = TRUE))))

# ============================================================
# FIGURES 3 & 4 ALTERNATIVE — N surplus on y-axis
# ============================================================
# Y-axis: N surplus per acre = (Total_N_Actual - Total_N_Reduced) / Average_Area
# All other aesthetics identical to the N application rate versions.

fig_bubble_nsurplus <- ggplot(
    mapping = aes(x = mean_ph_gap, y = mean_n_surplus_per_acre,
                  size = mean_avoided_per_acre, fill = Crop)
  ) +
  geom_point(data = filter(bubble_crop, ef_model == "Wang"),
             aes(color = model_label), shape = 21, alpha = 0.45, stroke = 0.5) +
  geom_point(data = filter(bubble_crop, ef_model == "Qiu"),
             aes(color = model_label), shape = 21, alpha = 0.85, stroke = 0.7) +
  geom_text_repel(data = filter(bubble_crop, ef_model == "Wang"),
                  aes(label = Crop), size = 3.2, fontface = "bold",
                  show.legend = FALSE, segment.color = NA,
                  box.padding = 0.8, point.padding = 1.0, max.overlaps = Inf) +
  scale_size_continuous(name = "Avoided N\u2082O-N\n(kg/acre)",
                        range = c(3, 18), breaks = c(0.1, 0.25, 0.5, 1.0)) +
  scale_fill_manual(values = crop_colors, guide = "none") +
  scale_color_manual(
    name   = "N\u2082O model",
    values = model_borders,
    labels = c("Linear model (Wang)" = "Linear model", "Quadratic model (Qiu)" = "Quadratic model"),
    guide  = guide_legend(override.aes = list(size = 5, shape = 21, fill = "grey80",
                                              alpha = c(0.45, 0.85), stroke = c(0.5, 0.7)))
  ) +
  scale_x_continuous(expand = expansion(mult = 0.15)) +
  scale_y_continuous(expand = expansion(mult = c(0, 0.2)), limits = c(0, NA)) +
  labs(
    x       = "Soil pH gap",
    y       = "N surplus after 50% reduction (kg N/acre)",
    caption = paste0(
      "Each crop shown as two concentric circles: outer (transparent) = Linear model (Wang); inner (opaque) = Quadratic model (Qiu).\n",
      "Position is area-weighted national mean: x-axis = max recommended pH \u2212 current EBK pH; y-axis = N surplus (N actual \u2212 N reduced per acre).\n",
      "Bubble size proportional to area-weighted mean avoided N\u2082O-N per harvested acre.\n",
      "EBK soil pH model; max recommended pH target; combined scenario (pH management + N reduction)."
    )
  ) +
  theme_bw() +
  theme(legend.position       = "right",
        plot.caption          = element_text(size = 8, hjust = 0, color = "grey35",
                                             margin = margin(t = 6), lineheight = 1.3),
        plot.caption.position = "plot")

ggsave("plots/figures/fig3_phgap_nsurplus.png", fig_bubble_nsurplus,
       width = 9, height = 6, dpi = 300)
message("Saved fig3_phgap_nsurplus")

fig_bubble_share_nsurplus <- ggplot(bubble_share,
