                       midpoint = 0.5, limits = c(0, 1),
                       name = "pH management\nshare", labels = scales::percent) +
  scale_size_continuous(name = "Avoided N\u2082O-N\n(kg/acre)",
                        range = c(3, 18), breaks = c(0.1, 0.25, 0.5, 1.0)) +
  scale_x_continuous(expand = expansion(mult = 0.15)) +
  scale_y_continuous(expand = expansion(mult = 0.15)) +
  labs(
    x       = "Soil pH gap",
    y       = "N surplus after 50% reduction (kg N/acre)",
    caption = paste0(
      "Each bubble = one crop. Position is area-weighted national mean: x-axis = max recommended pH \u2212 current EBK pH; y-axis = N surplus (N actual \u2212 N reduced per acre).\n",
      "Bubble size proportional to area-weighted mean avoided N\u2082O-N per harvested acre.\n",
      "Fill color shows the fraction of combined avoided N\u2082O-N attributable to pH management (purple) vs N reduction (green).\n",
      "EBK soil pH model; max recommended pH target; combined scenario (pH management + N reduction)."
    )
  ) +
  theme_bw() +
  theme(legend.position       = "right",
        plot.caption          = element_text(size = 8, hjust = 0, color = "grey35",
                                             margin = margin(t = 6), lineheight = 1.3),
        plot.caption.position = "plot")

ggsave("plots/supporting_figures/fig4_phshare_nsurplus.png", fig_bubble_share_nsurplus,
       width = 11, height = 6, dpi = 300)
message("Saved fig4_phshare_nsurplus (supporting figures)")

# ============================================================
# FIGURE 5 — CUMULATIVE AVOIDED N2O BY COUNTY RANK
# ============================================================
# Counties ranked from highest to lowest avoided N2O (pH management only).
# Cumulative curve shows how quickly total avoided emissions plateau as
# lower-impact counties are added — answering: how many counties capture
# most of the potential benefit?
#
# EBK pH model. Two lines per panel: Avg and Max pH targets.
# Two panels: linear (Wang) and quadratic (Qiu) EF models.
# Qiu: negative avoided values (net N2O increase from liming) set to zero before ranking.

# Sum to county level and pivot to long format so pH-only, combined, and N-only
# scenarios can be ranked and cumulated separately. Qiu filter already applied
# in data_prep.R — no clipping needed here.
# N-only does not vary by pH target so it is computed separately and bound in.
cumulative_dat <- components |>
  filter(ph_model == "EBK") |>
  group_by(State, County, ef_model, ph_target) |>
  summarise(
    pH_only  = sum(pH_only,  na.rm = TRUE) / 1e6,
    combined = sum(combined, na.rm = TRUE) / 1e6,
    .groups = "drop"
  ) |>
  pivot_longer(c(pH_only, combined), names_to = "scenario", values_to = "avoided_ktN") |>
  bind_rows(
    # N-only: independent of pH target; filter to one ph_target to avoid
    # double-counting (N_only is identical across Avg and Max rows)
    components |>
      filter(ph_model == "EBK", ph_target == "Max") |>
      group_by(State, County, ef_model) |>
      summarise(avoided_ktN = sum(N_only, na.rm = TRUE) / 1e6, .groups = "drop") |>
      mutate(ph_target = "N_only", scenario = "N_only")
  ) |>
  # Rank counties independently within each ef_model × ph_target × scenario group
  arrange(ef_model, ph_target, scenario, desc(avoided_ktN)) |>
  group_by(ef_model, ph_target, scenario) |>
  mutate(
    county_rank    = row_number(),
    cumulative_ktN = cumsum(avoided_ktN)
  ) |>
  ungroup() |>
  mutate(
    ef_label = factor(recode(ef_model, !!!model_labels), levels = unname(model_labels)),
    ph_label = factor(ph_target,
                      levels = c("Avg", "Max", "N_only"),
                      labels = c("Average pH", "Maximum pH", "Current pH")),
    scenario_label = factor(scenario,
                            levels = c("pH_only", "combined", "N_only"),
                            labels = c("pH management only", "Combined", "N reduction only"))
  )

# ── Spearman rank correlations ────────────────────────────────────────────────
# Two comparisons, both using Combined scenario, EBK pH model:
#   (1) Avg vs Max pH target — does the choice of target change county priorities?
#   (2) Wang vs Qiu EF model — does model choice change county priorities?

county_combined <- cumulative_dat |>
  filter(scenario == "combined", ph_target %in% c("Avg", "Max"))

# (1) Avg vs Max pH target, within each EF model
cat("\n── Spearman: Avg vs Max pH target (Combined scenario) ──\n")
for (m in c("Wang", "Qiu")) {
  wide <- county_combined |>
    filter(ef_model == m) |>
    select(State, County, ph_target, county_rank) |>
    pivot_wider(names_from = ph_target, values_from = county_rank) |>
    filter(!is.na(Avg), !is.na(Max))
  rho     <- cor(wide$Avg, wide$Max, method = "spearman")
  top_avg <- wide |> slice_min(Avg, n = 100) |> pull(County)
  top_max <- wide |> slice_min(Max, n = 100) |> pull(County)
  overlap <- sum(top_avg %in% top_max)
  cat(sprintf("  %s: rho = %.3f | top-100 overlap = %d/100 (n = %d)\n",
              m, rho, overlap, nrow(wide)))
}

# (2) Wang vs Qiu EF model, Max pH target
cat("\n── Spearman: Wang vs Qiu EF model (Combined, Max pH) ──\n")
wide_models <- county_combined |>
  filter(ph_target == "Max") |>
  select(State, County, ef_model, county_rank) |>
  pivot_wider(names_from = ef_model, values_from = county_rank) |>
  filter(!is.na(Wang), !is.na(Qiu))
rho_models  <- cor(wide_models$Wang, wide_models$Qiu, method = "spearman")
top_wang    <- wide_models |> slice_min(Wang, n = 100) |> pull(County)
top_qiu     <- wide_models |> slice_min(Qiu,  n = 100) |> pull(County)
overlap_mod <- sum(top_wang %in% top_qiu)
cat(sprintf("  Wang vs Qiu: rho = %.3f | top-100 overlap = %d/100 (n = %d)\n",
            rho_models, overlap_mod, nrow(wide_models)))

# Color = pH target; linetype = scenario
cumul_colors    <- c("Average pH" = "#fec44f", "Maximum pH" = "#7f2704",
                     "Current pH" = "grey50")
cumul_linetypes <- c("pH management only" = "dashed", "Combined" = "solid",
                     "N reduction only" = "dotted")

# ── Figure 5: shared absolute threshold version ────────────────────────────────
# Instead of each curve's own 80% threshold, all drop lines point to the same
# absolute y-value: 50% of the best scenario's total (Wang combined Max).
# Curves that never reach the threshold (most pH-only scenarios) have no marker.
# The shared horizontal reference line makes x-positions directly comparable:
# how many counties does each scenario need to hit the same mitigation target?

shared_threshold <- 0.5 * max(
  cumulative_dat |>
    group_by(ef_model, ph_target, scenario) |>
    summarise(total = max(cumulative_ktN), .groups = "drop") |>
    pull(total)
)

threshold_shared <- cumulative_dat |>
  group_by(ef_model, ph_target, scenario, ef_label, ph_label, scenario_label) |>
  filter(max(cumulative_ktN) >= shared_threshold,   # skip curves that never reach it
         cumulative_ktN >= shared_threshold) |>
  slice_min(county_rank) |>
  ungroup()

fig_cumulative_shared <- ggplot(cumulative_dat,
    aes(x = county_rank, y = cumulative_ktN,
        color = ph_label, linetype = scenario_label)
  ) +
  geom_line(linewidth = 0.9) +
  # Horizontal reference line showing the shared target
  geom_hline(yintercept = shared_threshold, linetype = "dotted",
             color = "grey40", linewidth = 0.5) +
  # Vertical drop to x-axis at the shared threshold for each eligible curve
  geom_segment(data = threshold_shared,
               aes(x = county_rank, xend = county_rank,
                   y = 0, yend = shared_threshold),
               linetype = "dotted", linewidth = 0.5, show.legend = FALSE) +
  # Point at the intersection of each curve and the shared threshold
  geom_point(data = threshold_shared,
             aes(y = shared_threshold, shape = "50% of maximum\npotential"),
             size = 1.8, fill = "white", stroke = 1.2) +
  facet_wrap(~ef_label, ncol = 2) +
  scale_color_manual(name = "pH target", values = cumul_colors,
                     guide = guide_legend(override.aes = list(shape = NA))) +
  scale_linetype_manual(name = "Scenario", values = cumul_linetypes) +
  scale_shape_manual(
    name   = NULL,
    values = c("50% of maximum\npotential" = 21),
    guide  = guide_legend(override.aes = list(color = "grey30", fill = "white",
                                              size = 2, stroke = 1.2))
  ) +
  scale_x_continuous(labels = scales::comma,
                     expand = expansion(mult = c(0.01, 0.03))) +
  scale_y_continuous(expand = expansion(mult = c(0, 0.05))) +
  labs(
    x       = "Number of counties",
    y       = "Cumulative avoided N\u2082O-N (kt)",
    caption = paste0(
      "EBK soil pH model. Counties ranked independently within each scenario ",
      "by avoided N\u2082O-N, highest to lowest.\n",
      "Combined scenario: liming to recommended pH target + 50% reduction in N surplus. ",
      "N reduction only: 50% reduction in N surplus, no pH change (reference line).\n",
      sprintf("Dotted horizontal line = shared mitigation target (%.1f kt N\u2082O-N; ", shared_threshold),
      "50% of the maximum scenario total). Vertical drop lines show the number of counties ",
      "needed to reach this target; curves that never reach it have no marker.\n",
      "Quadratic model: counties where liming results in a net increase in N\u2082O (avoided emissions < 0) set to zero."
    )
  ) +
  theme_bw() +
  theme(
    legend.position       = "right",
    legend.key.width      = unit(1.2, "cm"),
    plot.caption          = element_text(size = 8, hjust = 0, color = "grey35",
                                         margin = margin(t = 6), lineheight = 1.3),
    plot.caption.position = "plot"
  )

ggsave("plots/figures/fig5_cumulative_county.png", fig_cumulative_shared,
       width = 10, height = 5, dpi = 300)
message("Saved fig5_cumulative_county")

message("\nAll main figures saved to plots/figures/")
